void main() {
  // Lists
  var list = [1, 2, 3];
  list.add(4);
  print(list);          // [1, 2, 3, 4]
  print(list.length);   // 4

  // Sets
  var set = {1, 2, 3};
  set.add(3);           // no effect (already present)
  print(set);           // {1, 2, 3}

  // Maps
  var map = {'a': 1, 'b': 2};
  map['c'] = 3;
  print(map['b']);      // 2
  print(map.containsKey('d')); // false
}

